const productImageLookup = {};
for (const item of $input.all()) {
  const image = item.json;
  // Extract filename from URL (e.g., https://cdn.shopify.com/s/files/1/0000/0000/files/image_filename.jpg?v=...) 
  const url = new URL(image.src);
  const pathnameParts = url.pathname.split('/');
  const filenameWithExtension = pathnameParts[pathnameParts.length - 1];

  if (filenameWithExtension) {
    productImageLookup[filenameWithExtension] = image.id;
  }
}
return [{ json: { productImageLookup } }];

const product = $input.item[0].json; // From Split Products
const productImageLookup = $input.item[1].json.productImageLookup; // From Code: Build Image Lookup
const globalStyleMapping = $input.item[2].json.globalStyleMapping; // From Set Global Style Map

const variantUpdates = [];

for (const variant of product.variants) {
  let styleName = null;
  // Example regex to extract style name from variant title, assuming pattern like "Style Name - Age Variant"
  // Adjust this regex based on your actual variant title patterns.
  // e.g., "Round neck / Short sleeve / With pant - 6-12 months" -> "Round neck / Short sleeve / With pant"
  const styleNameRegex = /^(.*?)(?: - \d{1,2}(?:–\d{1,2})? (?:months|years))?$/;
  const match = variant.title.match(styleNameRegex);
  if (match && match[1]) {
    styleName = match[1].trim();
  } else {
    styleName = variant.title.trim(); // Fallback to full title if no age pattern matched
  }

  if (styleName && globalStyleMapping[styleName]) {
    const styleFilenames = globalStyleMapping[styleName];
    const associatedImageIds = [];
    let primaryImageId = null;

    for (const filename of styleFilenames) {
      // Ensure we compare clean filenames without query parameters or paths
      const cleanFilename = filename.split('?')[0].split('/').pop();
      const imageId = productImageLookup[cleanFilename];
      if (imageId) {
        associatedImageIds.push(imageId);
        if (!primaryImageId) {
          primaryImageId = imageId; // Set the first found image as the primary variant image
        }
      }
    }

    if (associatedImageIds.length > 0) {
      variantUpdates.push({
        json: {
          variantId: variant.id,
          variant_update_payload: {
            id: variant.id,
            image_id: primaryImageId, // Link the variant to its primary style image
            metafields: [
              {
                key: 'associated_image_ids',
                namespace: 'custom',
                value: JSON.stringify(associatedImageIds), // Store all associated image IDs as a JSON string
                type: 'list.number_integer' // Critical for Shopify to interpret as a list of numbers
              }
            ]
          }
        }
      });
    } else {
      console.warn(`[WARNING] No images found in Shopify for style "${styleName}" of product "${product.title}" (ID: ${product.id}) for variant "${variant.title}" (ID: ${variant.id}). No update applied.`);
      // Log this to Google Sheets or Slack if needed for variants that don't find images
    }
  } else {
    console.warn(`[WARNING] Style "${styleName}" (from variant title "${variant.title}") not found in global mapping for product "${product.title}" (ID: ${product.id}). No update applied.`);
    // Log this to Google Sheets or Slack if needed for variants that don't match any style
  }
}

return variantUpdates;
